import React, { useState, useEffect, useRef } from "react";
import { PRIORITY_META, STATUS_META, PRIORITIES, STATUSES } from "../utils/costants";

const EMPTY = { title: "", description: "", priority: "Medium", status: "Open" };

export default function FeatureModal({ feature, onSave, onClose }) {
  const [form, setForm] = useState(feature ? { ...feature } : { ...EMPTY });
  const [errors, setErrors] = useState({});
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(feature?.image ? `http://localhost:5000/api/features/images/${feature.image}` : null);

  const titleRef = useRef(null);
  const fileInputRef = useRef(null);
  const isEdit = Boolean(feature);

  useEffect(() => {
    titleRef.current?.focus();
  }, []);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  function validate() {
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required.";
    else if (form.title.trim().length < 3) errs.title = "Must be at least 3 characters.";
    if (!form.description.trim()) errs.description = "Description is required.";
    return errs;
  }

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
    if (errors[name]) setErrors((er) => ({ ...er, [name]: undefined }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }
    onSave({ ...form, image: imageFile });
    onClose();
  }

  function handleImageChange(e) {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setImagePreview(event.target.result);
      };
      reader.readAsDataURL(file);
    }
  }

  function removeImage() {
    setImageFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        background: "rgba(0, 0, 0, 0.6)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px",
      }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        style={{
          background: "white",
          borderRadius: "12px",
          boxShadow: "0 20px 60px rgba(0, 0, 0, 0.3)",
          maxWidth: "700px",
          width: "100%",
          maxHeight: "90vh",
          overflow: "auto",
        }}
      >
        {/* Header */}
        <div
          style={{
            background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
            padding: "32px",
            borderRadius: "12px 12px 0 0",
            color: "white",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <div>
            <h1 style={{ margin: "0", fontSize: "28px", fontWeight: 700 }}>
              {isEdit ? "Edit Feature" : "Add New Feature"}
            </h1>
            <p style={{ margin: "8px 0 0", fontSize: "14px", opacity: 0.9 }}>
              {isEdit ? "Update the feature details" : "Create a new feature request"}
            </p>
          </div>
          <button
            onClick={onClose}
            style={{
              background: "rgba(255, 255, 255, 0.2)",
              border: "none",
              fontSize: "24px",
              cursor: "pointer",
              color: "white",
              padding: "8px 12px",
              width: "40px",
              height: "40px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              borderRadius: "8px",
              transition: "background 0.2s",
            }}
            onMouseOver={(e) => e.target.style.background = "rgba(255, 255, 255, 0.3)"}
            onMouseOut={(e) => e.target.style.background = "rgba(255, 255, 255, 0.2)"}
          >
            ✕
          </button>
        </div>

        {/* Form Body */}
        <form onSubmit={handleSubmit} style={{ padding: "32px" }}>
          {/* Title */}
          <div style={{ marginBottom: "24px" }}>
            <label style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", display: "block", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.5px" }}>
              Title
            </label>
            <input
              ref={titleRef}
              name="title"
              type="text"
              value={form.title}
              onChange={handleChange}
              placeholder="Enter feature title..."
              style={{
                width: "100%",
                padding: "12px 14px",
                border: `2px solid ${errors.title ? "#ef5350" : "#e5e7eb"}`,
                borderRadius: "8px",
                fontSize: "14px",
                fontFamily: "inherit",
                boxSizing: "border-box",
                transition: "border-color 0.2s",
              }}
            />
            {errors.title && <p style={{ color: "#ef5350", fontSize: "12px", margin: "6px 0 0" }}>{errors.title}</p>}
          </div>

          {/* Description */}
          <div style={{ marginBottom: "24px" }}>
            <label style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", display: "block", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.5px" }}>
              Description
            </label>
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              placeholder="Describe the feature in detail..."
              rows={4}
              style={{
                width: "100%",
                padding: "12px 14px",
                border: `2px solid ${errors.description ? "#ef5350" : "#e5e7eb"}`,
                borderRadius: "8px",
                fontSize: "14px",
                fontFamily: "inherit",
                boxSizing: "border-box",
                resize: "vertical",
                transition: "border-color 0.2s",
              }}
            />
            {errors.description && <p style={{ color: "#ef5350", fontSize: "12px", margin: "6px 0 0" }}>{errors.description}</p>}
          </div>

          {/* Priority & Status */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px", marginBottom: "24px" }}>
            <div>
              <label style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", display: "block", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.5px" }}>
                Priority
              </label>
              <select
                name="priority"
                value={form.priority}
                onChange={handleChange}
                style={{
                  width: "100%",
                  padding: "12px 14px",
                  border: "2px solid #e5e7eb",
                  borderRadius: "8px",
                  fontSize: "14px",
                  fontFamily: "inherit",
                  boxSizing: "border-box",
                  cursor: "pointer",
                }}
              >
                {PRIORITIES.map((p) => (
                  <option key={p} value={p}>{p}</option>
                ))}
              </select>
            </div>
            <div>
              <label style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", display: "block", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.5px" }}>
                Status
              </label>
              <select
                name="status"
                value={form.status}
                onChange={handleChange}
                style={{
                  width: "100%",
                  padding: "12px 14px",
                  border: "2px solid #e5e7eb",
                  borderRadius: "8px",
                  fontSize: "14px",
                  fontFamily: "inherit",
                  boxSizing: "border-box",
                  cursor: "pointer",
                }}
              >
                {STATUSES.map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Image Upload */}
          <div style={{ marginBottom: "24px" }}>
            <label style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", display: "block", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.5px" }}>
              Image (Optional)
            </label>
            {imagePreview ? (
              <div style={{ marginBottom: "12px" }}>
                <img
                  src={imagePreview}
                  alt="preview"
                  style={{
                    maxWidth: "100%",
                    maxHeight: "200px",
                    borderRadius: "8px",
                    marginBottom: "12px",
                    border: "1px solid #e5e7eb",
                  }}
                />
                <button
                  type="button"
                  onClick={removeImage}
                  style={{
                    background: "#fee2e2",
                    color: "#dc2626",
                    border: "none",
                    padding: "8px 16px",
                    borderRadius: "6px",
                    cursor: "pointer",
                    fontSize: "13px",
                    fontWeight: 600,
                  }}
                >
                  Remove Image
                </button>
              </div>
            ) : (
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                style={{
                  width: "100%",
                  padding: "12px 14px",
                  border: "2px dashed #e5e7eb",
                  borderRadius: "8px",
                  cursor: "pointer",
                }}
              />
            )}
          </div>

          {/* Buttons */}
          <div style={{ display: "flex", gap: "12px" }}>
            <button
              type="submit"
              style={{
                flex: 1,
                padding: "12px 16px",
                background: "#667eea",
                border: "none",
                borderRadius: "8px",
                fontSize: "15px",
                fontWeight: 600,
                cursor: "pointer",
                color: "white",
                transition: "background 0.2s",
              }}
              onMouseOver={(e) => e.target.style.background = "#764ba2"}
              onMouseOut={(e) => e.target.style.background = "#667eea"}
            >
              {isEdit ? "Update Feature" : "Create Feature"}
            </button>
            <button
              type="button"
              onClick={onClose}
              style={{
                flex: 1,
                padding: "12px 16px",
                background: "#f3f4f6",
                border: "2px solid #d1d5db",
                borderRadius: "8px",
                fontSize: "15px",
                fontWeight: 600,
                cursor: "pointer",
                color: "#1f2937",
                transition: "background 0.2s",
              }}
              onMouseOver={(e) => e.target.style.background = "#e5e7eb"}
              onMouseOut={(e) => e.target.style.background = "#f3f4f6"}
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
